func (i *CreateImportJobInteractor) Execute(ctx context.Context, 
    req *input.CreateImportJobRequest) (*input.CreateImportJobResponse, error) {
    // Validation
    if err := i.validateWebhookURL(*req.WebhookURL); err != nil {
        return nil, err
    }
    // Parse CSV
